remarks.code:
// Enable Trace feature:
DDTrace.Enable(DDTraceConfiguration);

// Use Tracer:
DDTracer.Shared.StartSpan(...);

var request = new HttpRequestMessage(...);

var writer = new DDW3CHTTPHeadersWriter();
var span = DDTracer.Shared.StartSpan("network request");
DDTracer.Shared.Inject(span.Context, OT.FormatTextMap, writer);

foreach (var (field, value) in writer.TraceHeaderFields)
{
    request.Headers.Add(field, value);
}

// call span.Finish() when the request completes

foreach (var (field, value) in writer.TraceHeaderFields)
{
    request.Headers.Add(field, value);
}
